#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int countPartitions(vector<int>& arr, int diff) {
        int total = accumulate(arr.begin(), arr.end(), 0);
        unordered_map<int, int> dp = {{0, 1}};
        int s = 0;
        int res = 0;
        for (int num : arr) {
            s += num;
            res += dp.count(s - diff) ? dp[s - diff] : 0;
            dp[s]++;
        }
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> arr(n);
    for (int i = 0; i < n; i++) cin >> arr[i];
    int diff;
    if (!(cin >> diff)) return 0;
    Solution sol;
    int ans = sol.countPartitions(arr, diff);
    cout << ans << "\n";
    return 0;
}
